import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import {
  LayoutDashboard, FlaskConical, Users, BarChart3, Settings,
  Bell, ChevronDown, LogOut, Menu, Plus, Search, Briefcase,
  User, Shield, CheckCircle, DollarSign
} from 'lucide-react';
import NyvelMark from '../ui/NyvelMark';
import { useAuth } from '../../App';

const companyNav = [
  { label: 'Dashboard', icon: LayoutDashboard, href: '/company/dashboard' },
  { label: 'My Tests', icon: FlaskConical, href: '/company/tests' },
  { label: 'Create Test', icon: Plus, href: '/company/create-test' },
  { label: 'Testers', icon: Users, href: '/company/testers' },
  { label: 'Reports', icon: BarChart3, href: '/company/reports' },
  { label: 'Settings', icon: Settings, href: '/company/settings' },
];

const testerNav = [
  { label: 'Dashboard', icon: LayoutDashboard, href: '/tester/dashboard' },
  { label: 'Available Tests', icon: Search, href: '/tester/tests' },
  { label: 'My Applications', icon: CheckCircle, href: '/tester/applications' },
  { label: 'Earnings', icon: DollarSign, href: '/tester/earnings' },
  { label: 'My Profile', icon: User, href: '/tester/profile' },
  { label: 'Settings', icon: Settings, href: '/tester/settings' },
];

const adminNav = [
  { label: 'Overview', icon: LayoutDashboard, href: '/admin/dashboard' },
  { label: 'Users', icon: Users, href: '/admin/users' },
  { label: 'Tests', icon: FlaskConical, href: '/admin/tests' },
  { label: 'Reports', icon: BarChart3, href: '/admin/reports' },
  { label: 'Security', icon: Shield, href: '/admin/security' },
  { label: 'Settings', icon: Settings, href: '/admin/settings' },
];

const navByRole = { company: companyNav, tester: testerNav, admin: adminNav };

const roleConfig = {
  company: { label: 'Company', icon: Briefcase, color: 'text-brand-400', bg: 'bg-brand-600/20' },
  tester: { label: 'Tester', icon: User, color: 'text-accent-400', bg: 'bg-accent-600/20' },
  admin: { label: 'Admin', icon: Shield, color: 'text-amber-400', bg: 'bg-amber-600/20' },
};

export default function PlatformLayout({ children, title }) {
  const { user, logout, login } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const userMenuRef = useRef(null);

  useEffect(() => {
    if (!userMenuOpen) return;
    const handleClick = (e) => {
      if (userMenuRef.current && !userMenuRef.current.contains(e.target)) {
        setUserMenuOpen(false);
      }
    };
    const handleKey = (e) => {
      if (e.key === 'Escape') setUserMenuOpen(false);
    };
    document.addEventListener('mousedown', handleClick);
    document.addEventListener('keydown', handleKey);
    return () => {
      document.removeEventListener('mousedown', handleClick);
      document.removeEventListener('keydown', handleKey);
    };
  }, [userMenuOpen]);

  const nav = navByRole[user?.role] || companyNav;
  const rc = roleConfig[user?.role] || roleConfig.company;
  const RoleIcon = rc.icon;

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const switchRole = (role) => {
    login(role);
    const destinations = { company: '/company/dashboard', tester: '/tester/dashboard', admin: '/admin/dashboard' };
    navigate(destinations[role]);
    setUserMenuOpen(false);
  };

  const Sidebar = () => (
    <aside className="flex flex-col h-full bg-slate-950 border-r border-white/10 w-64 flex-shrink-0">
      {/* Logo */}
      <div className="flex items-center gap-2.5 px-5 h-16 border-b border-white/10 flex-shrink-0">
        <NyvelMark size={28} className="rounded-lg" />
        <span className="font-display font-bold text-white text-base tracking-tight">
          Ny<span className="text-brand-400">vel</span>
        </span>
        <div className={`ml-auto px-2 py-0.5 rounded-md text-xs font-semibold ${rc.bg} ${rc.color}`}>
          {rc.label}
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 py-4 space-y-0.5 overflow-y-auto">
        {nav.map(({ label, icon: Icon, href }) => {
          const isActive = location.pathname === href;
          return (
            <Link
              key={label}
              to={href}
              onClick={() => setSidebarOpen(false)}
              className={`sidebar-link ${isActive ? 'active' : ''}`}
            >
              <Icon size={18} className="flex-shrink-0" />
              {label}
            </Link>
          );
        })}
      </nav>

      {/* User section */}
      <div className="px-3 py-4 border-t border-white/10 flex-shrink-0">
        {/* Role switcher for MVP demo */}
        <div className="mb-3 px-3 py-2 rounded-lg bg-slate-800/60">
          <p className="text-[10px] text-slate-500 font-semibold uppercase tracking-widest mb-2">
            Demo: Switch Role
          </p>
          <div className="flex gap-1">
            {['company', 'tester', 'admin'].map((r) => (
              <button
                key={r}
                onClick={() => switchRole(r)}
                className={`flex-1 py-1 text-xs rounded-md font-medium transition-all capitalize
                  ${user?.role === r ? 'bg-brand-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
              >
                {r === 'company' ? '🏢' : r === 'tester' ? '👤' : '🛡️'}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-2.5 px-2 py-2 rounded-lg hover:bg-slate-800 cursor-pointer group transition-colors">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-brand-500 to-accent-500 flex items-center justify-center text-white text-xs font-bold flex-shrink-0">
            {user?.name?.split(' ').map((n) => n[0]).join('') || 'U'}
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-xs font-semibold text-white truncate">{user?.name}</p>
            <p className="text-[10px] text-slate-500 truncate">{user?.email}</p>
          </div>
          <button
            onClick={handleLogout}
            className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-400 transition-all"
            title="Sign out"
          >
            <LogOut size={14} />
          </button>
        </div>
      </div>
    </aside>
  );

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Desktop sidebar */}
      <div className="hidden lg:flex flex-col">
        <Sidebar />
      </div>

      {/* Mobile sidebar overlay */}
      {sidebarOpen && (
        <div className="lg:hidden fixed inset-0 z-50 flex">
          <div className="absolute inset-0 bg-black/50" onClick={() => setSidebarOpen(false)} />
          <div className="relative flex flex-col">
            <Sidebar />
          </div>
        </div>
      )}

      {/* Main content area */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Top header */}
        <header className="h-16 bg-white border-b border-slate-100 flex items-center px-4 sm:px-6 gap-4 flex-shrink-0">
          {/* Mobile sidebar toggle */}
          <button
            className="lg:hidden text-slate-500 hover:text-slate-700 p-1"
            onClick={() => setSidebarOpen(true)}
          >
            <Menu size={22} />
          </button>

          <div className="flex-1">
            <h1 className="font-display font-bold text-slate-900 text-lg">{title}</h1>
          </div>

          <div className="flex items-center gap-3">
            <button className="relative p-2 rounded-lg text-slate-500 hover:bg-slate-100 hover:text-slate-700 transition-colors">
              <Bell size={20} />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 rounded-full bg-brand-500" />
            </button>

            <div className="h-6 w-px bg-slate-200" />

            <div className="relative" ref={userMenuRef}>
              <button
                onClick={() => setUserMenuOpen(!userMenuOpen)}
                aria-expanded={userMenuOpen}
                aria-haspopup="true"
                className="flex items-center gap-2 pl-1 pr-3 py-1 rounded-xl hover:bg-slate-100 transition-colors"
              >
                <div className="w-7 h-7 rounded-full bg-gradient-to-br from-brand-500 to-accent-500 flex items-center justify-center text-white text-xs font-bold">
                  {user?.name?.split(' ').map((n) => n[0]).join('') || 'U'}
                </div>
                <span className="text-sm font-semibold text-slate-700 hidden sm:block">{user?.name?.split(' ')[0]}</span>
                <ChevronDown size={14} className="text-slate-400" />
              </button>

              {userMenuOpen && (
                <div className="absolute right-0 top-full mt-2 w-52 bg-white border border-slate-100 rounded-xl shadow-lg py-1 z-20">
                  <div className="px-3 py-2 border-b border-slate-100">
                    <p className="text-xs font-semibold text-slate-900">{user?.name}</p>
                    <p className="text-xs text-slate-500">{user?.email}</p>
                  </div>
                  <button
                    onClick={handleLogout}
                    className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors"
                  >
                    <LogOut size={14} />
                    Sign Out
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Page content */}
        <main className="flex-1 overflow-y-auto">
          {children}
        </main>
      </div>
    </div>
  );
}
